import React from "react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const VerticalGraph = ({ data }) => {
  if (!data || !data.labels?.length) {
    return <p style={{ textAlign: "center" }}>No graph data available</p>;
  }

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    animation: {
      duration: 1200,
      easing: "easeOutQuart",
    },
    plugins: {
      legend: {
        position: "top",
        labels: {
          color: "#333",
          font: {
            size: 13,
            weight: "600",
          },
        },
      },
      title: {
        display: true,
        text: "Portfolio Price Comparison",
        color: "#222",
        font: {
          size: 18,
          weight: "bold",
        },
        padding: {
          top: 10,
          bottom: 30,
        },
      },
      tooltip: {
        backgroundColor: "#111",
        titleColor: "#fff",
        bodyColor: "#fff",
        padding: 12,
        borderWidth: 1,
        borderColor: "#333",
      },
    },
    scales: {
      x: {
        ticks: {
          color: "#555",
          font: {
            weight: "500",
          },
        },
        grid: {
          display: false,
        },
      },
      y: {
        ticks: {
          color: "#555",
        },
        grid: {
          color: "rgba(0,0,0,0.05)",
        },
      },
    },
  };

  return (
    <div
      style={{
        width: "100%",
        maxWidth: "1000px",
        height: "450px",
        margin: "60px auto",
        padding: "30px",
        background: "#ffffff",
        borderRadius: "20px",
        boxShadow: "0 20px 50px rgba(0,0,0,0.08)",
      }}
    >
      <Bar options={options} data={data} />
    </div>
  );
};

export default VerticalGraph;
